300	function planFloorRoofOutlineWireGroup(
301	  outlineMm: Array<{ xMm: number; yMm: number }>,
302	  opts: {
303	    kind: 'floor' | 'roof';
304	    pickId: string;
305	    lineWeightHint: number;
306	    linePatternToken?: string | null;
307	    roofGeometrySupportToken?: string | null;
308	  },
309	): THREE.Group {
310	  const grp = new THREE.Group();
311	  const palette = getPlanPalette();
312	  const color = opts.kind === 'floor' ? palette.floorOutline : palette.roofOutline;
313	  const fillY = opts.kind === 'floor' ? PLAN_Y + 0.001 : PLAN_Y + 0.004;
314	  const strokeY = fillY + 0.0004;
315	  const baseOp = opts.kind === 'floor' ? PLAN_FLOOR_FILL_OPACITY_BASE : PLAN_ROOF_FILL_OPACITY_BASE;
316	  const lwh =
317	    Number.isFinite(opts.lineWeightHint) && opts.lineWeightHint > 0 ? opts.lineWeightHint : 1;
318	  const fillOpacity = Math.min(0.34, Math.max(0.06, baseOp * Math.min(1.35, lwh / 1.12)));
319	  grp.add(horizontalOutlineMesh(outlineMm, fillY, color, fillOpacity, opts.pickId));
320	
321	  if (outlineMm.length < 2) {
322	    grp.userData.bimPickId = opts.pickId;
323	    if (opts.kind === 'roof' && opts.roofGeometrySupportToken) {
324	      grp.userData.bimAiRoofGeometrySupportToken = opts.roofGeometrySupportToken;
325	    }
326	    return grp;
327	  }
328	
329	  const pts = outlineMm.map((p) => new THREE.Vector3(ux(p.xMm), strokeY, uz(p.yMm)));
330	  const dashSpec = planLinePatternDashWorldUnits(opts.linePatternToken ?? undefined);
331	  if (dashSpec == null) {
332	    const loop = new THREE.LineLoop(
333	      new THREE.BufferGeometry().setFromPoints(pts),
334	      new THREE.LineBasicMaterial({ color, depthTest: true }),
335	    );
336	    loop.userData.bimPickId = opts.pickId;
337	    grp.add(loop);
338	  } else {
