export function stairPlanThree(
  stair: Extract<Element, { kind: 'stair' }>,
  elementsById?: Record<string, Element>,
  wireDoc?: StairPlanWireDocOverlays | null,
  detailLevel: PlanDetailLevel = 'medium',
